## Common patterns

### Like/Favorite functionality

Common pattern for like or favorite actions with visual feedback:

```jsx-live-dev
const App = () => {
  const [liked, setLiked] = useState(false);
  const [favorited, setFavorited] = useState(false);
  const [saved, setSaved] = useState(false);

  return (
    <Stack direction="column" gap="400">
      <Stack direction="row" gap="400" alignItems="center">
        <ToggleButton
          isSelected={liked}
          onChange={setLiked}
          colorPalette="critical"
          aria-label="Like post"
        >
          <Icons.ThumbUp />
          {liked ? "Liked" : "Like"}
        </ToggleButton>
        {liked && (
          <Text fontSize="sm" color="critical.11">
            Thank you for your feedback!
          </Text>
        )}
      </Stack>

      <Stack direction="row" gap="400" alignItems="center">
        <ToggleButton
          isSelected={favorited}
          onChange={setFavorited}
          colorPalette="info"
          aria-label="Add to favorites"
        >
          <Icons.Star />
          {favorited ? "Favorited" : "Favorite"}
        </ToggleButton>
        {favorited && (
          <Text fontSize="sm" color="info.11">
            Added to your favorites
          </Text>
        )}
      </Stack>

      <Stack direction="row" gap="400" alignItems="center">
        <ToggleButton
          isSelected={saved}
          onChange={setSaved}
          aria-label="Save for later"
        >
          <Icons.Bookmark />
          {saved ? "Saved" : "Save"}
        </ToggleButton>
        {saved && (
          <Text fontSize="sm" color="neutral.11">
            Saved for later
          </Text>
        )}
      </Stack>
    </Stack>
  );
}
```

### Filter toggles

Use toggle buttons as filter controls in a toolbar or filter panel:

```jsx-live-dev
const App = () => {
  const [showActive, setShowActive] = useState(true);
  const [showInactive, setShowInactive] = useState(false);
  const [showArchived, setShowArchived] = useState(false);

  const getStatusText = () => {
    const statuses = [];
    if (showActive) statuses.push("Active");
    if (showInactive) statuses.push("Inactive");
    if (showArchived) statuses.push("Archived");
    return statuses.length > 0 ? statuses.join(", ") : "None";
  };

  return (
    <Stack direction="column" gap="400">
      <Text fontWeight="semibold">Filter by status:</Text>
      <Stack direction="row" gap="300" wrap="wrap">
        <ToggleButton
          size="xs"
          variant="outline"
          isSelected={showActive}
          onChange={setShowActive}
          colorPalette="primary"
        >
          Active
        </ToggleButton>

        <ToggleButton
          size="xs"
          variant="outline"
          isSelected={showInactive}
          onChange={setShowInactive}
          colorPalette="primary"
        >
          Inactive
        </ToggleButton>

        <ToggleButton
          size="xs"
          variant="outline"
          isSelected={showArchived}
          onChange={setShowArchived}
          colorPalette="primary"
        >
          Archived
        </ToggleButton>
      </Stack>
      <Text fontSize="sm" color="neutral.11">
        Showing: {getStatusText()}
      </Text>
    </Stack>
  );
}
```

