## Testing your implementation

These examples demonstrate how to test your implementation when using ToggleButton within your application. As the component's internal functionality is already tested by Nimbus, these patterns help you verify your integration and application-specific logic.

### Basic rendering tests

Verify the component renders with expected elements and states

```tsx
import { describe, it, expect, vi } from "vitest";
import { render, screen } from "@testing-library/react";
import userEvent from "@testing-library/user-event";
import { ToggleButton, NimbusProvider } from "@commercetools/nimbus";

describe("ToggleButton - Basic rendering", () => {
  it("renders toggle button with text content", () => {
    render(
      <NimbusProvider>
        <ToggleButton>Toggle Me</ToggleButton>
      </NimbusProvider>
    );

    const button = screen.getByRole("button", { name: /toggle me/i });
    expect(button).toBeInTheDocument();
  });

  it("renders in unselected state by default", () => {
    render(
      <NimbusProvider>
        <ToggleButton>Toggle</ToggleButton>
      </NimbusProvider>
    );

    const button = screen.getByRole("button");
    expect(button).toHaveAttribute("aria-pressed", "false");
  });

  it("renders with icon and text", () => {
    render(
      <NimbusProvider>
        <ToggleButton>
          <svg data-testid="test-icon" />
          Like
        </ToggleButton>
      </NimbusProvider>
    );

    expect(screen.getByTestId("test-icon")).toBeInTheDocument();
    expect(screen.getByRole("button", { name: /like/i })).toBeInTheDocument();
  });

  it("renders with different sizes", () => {
    const { rerender } = render(
      <NimbusProvider>
        <ToggleButton size="2xs">Extra Small</ToggleButton>
      </NimbusProvider>
    );

    let button = screen.getByRole("button");
    expect(button).toBeInTheDocument();

    rerender(
      <NimbusProvider>
        <ToggleButton size="xs">Small</ToggleButton>
      </NimbusProvider>
    );

    button = screen.getByRole("button");
    expect(button).toBeInTheDocument();

    rerender(
      <NimbusProvider>
        <ToggleButton size="md">Medium</ToggleButton>
      </NimbusProvider>
    );

    button = screen.getByRole("button");
    expect(button).toBeInTheDocument();
  });
});
```

### Interaction Tests

Test user interactions with the toggle button

```tsx
import { describe, it, expect, vi } from "vitest";
import { render, screen } from "@testing-library/react";
import userEvent from "@testing-library/user-event";
import { ToggleButton, NimbusProvider } from "@commercetools/nimbus";

describe("ToggleButton - Interactions", () => {
  it("toggles state when clicked", async () => {
    const user = userEvent.setup();
    const handleChange = vi.fn();

    render(
      <NimbusProvider>
        <ToggleButton onChange={handleChange}>Toggle</ToggleButton>
      </NimbusProvider>
    );

    const button = screen.getByRole("button");

    // Click to select
    await user.click(button);
    expect(handleChange).toHaveBeenCalledWith(true);
    expect(button).toHaveAttribute("aria-pressed", "true");

    // Click to unselect
    await user.click(button);
    expect(handleChange).toHaveBeenCalledWith(false);
    expect(button).toHaveAttribute("aria-pressed", "false");
  });

  it("toggles with keyboard (Enter)", async () => {
    const user = userEvent.setup();
    const handleChange = vi.fn();

    render(
      <NimbusProvider>
        <ToggleButton onChange={handleChange}>Toggle</ToggleButton>
      </NimbusProvider>
    );

    // Use userEvent.tab() instead of element.focus() to avoid act() warnings
    await user.tab();
    await user.keyboard("{Enter}");
    expect(handleChange).toHaveBeenCalledWith(true);
  });

  it("toggles with keyboard (Space)", async () => {
    const user = userEvent.setup();
    const handleChange = vi.fn();

    render(
      <NimbusProvider>
        <ToggleButton onChange={handleChange}>Toggle</ToggleButton>
      </NimbusProvider>
    );

    // Use userEvent.tab() instead of element.focus() to avoid act() warnings
    await user.tab();
    await user.keyboard(" ");
    expect(handleChange).toHaveBeenCalledWith(true);
  });

  it("is focusable with Tab key", async () => {
    const user = userEvent.setup();

    render(
      <NimbusProvider>
        <ToggleButton>Toggle</ToggleButton>
      </NimbusProvider>
    );

    const button = screen.getByRole("button");
    expect(button).not.toHaveFocus();

    await user.tab();
    expect(button).toHaveFocus();
  });
});
```

